INSERT INTO "PolicyUpdate" (id, title, source, date, excerpt, link, category, impact, "displayOrder", "isActive", "createdAt", "updatedAt")
VALUES
('policy-1', 'MeitY Releases Draft AI Ethics Framework for Public Consultation', 'MeitY', '2026-05-03', 'Ministry of Electronics and IT has released a comprehensive AI ethics framework covering fairness, transparency, accountability, and privacy. Public comments invited until June 15, 2026.', 'https://meity.gov.in', 'Policy', 'High', 0, true, NOW(), NOW()),
('policy-2', 'NITI Aayog Announces ₹500 Cr AI Research Fund for IITs', 'NITI Aayog', '2026-05-01', 'National Institution for Transforming India allocates ₹500 crore for AI research across 23 IITs. Focus areas include healthcare AI, agricultural AI, and climate modeling.', 'https://niti.gov.in', 'Funding', 'High', 1, true, NOW(), NOW()),
('policy-3', 'Digital Personal Data Protection Act: AI-Specific Guidelines Released', 'Data Protection Board', '2026-04-28', 'Data Protection Board of India issues guidelines for AI systems processing personal data. Mandates algorithmic transparency and user consent for automated decision-making.', 'https://dpb.gov.in', 'Regulation', 'High', 2, true, NOW(), NOW()),
('policy-4', 'AI Safety Standards Committee Publishes Testing Framework', 'Bureau of Indian Standards', '2026-04-25', 'Bureau of Indian Standards releases AI safety testing framework covering robustness, security, and bias evaluation. Voluntary compliance for now, mandatory from 2027.', 'https://bis.gov.in', 'Standards', 'Medium', 3, true, NOW(), NOW()),
('policy-5', 'Supreme Court Ruling: AI-Generated Evidence Admissibility Guidelines', 'Supreme Court of India', '2026-04-20', 'Landmark judgment establishes criteria for admitting AI-generated evidence in courts. Requires explainability, audit trails, and expert testimony on model reliability.', '#', 'Legal', 'High', 4, true, NOW(), NOW()),
('policy-6', 'MeitY Launches AI Compute Access Program for Startups', 'MeitY', '2026-04-18', 'New program provides subsidized access to GPU clusters for AI startups. Applications open for companies with < ₹10 Cr revenue. Up to 1000 GPU hours per quarter.', 'https://meity.gov.in', 'Policy', 'High', 5, true, NOW(), NOW());
INSERT INTO "AIResearcher" (id, name, university, position, "photoUrl", bio, "researchAreas", "notablePapers", "linkedinUrl", "googleScholarUrl", citations, "hIndex", "displayOrder", "isActive", "createdAt", "updatedAt")
