('researcher-3', 'Dr. Amit Patel', 'IISc Bangalore', 'Professor', NULL, 'Pioneering work in Reinforcement Learning and Robotics applications. Leading the AI for Manufacturing initiative at IISc.', ARRAY['Reinforcement Learning', 'Robotics', 'Autonomous Systems', 'Industrial AI'], ARRAY['RL for Industrial Automation (2025)', 'Multi-Agent Systems in Manufacturing (2024)', 'Safe Reinforcement Learning (2023)'], 'https://linkedin.com/in/amitpatel', 'https://scholar.google.com/amitpatel', 4200, 42, 2, true, NOW(), NOW()),
('researcher-4', 'Dr. Meera Reddy', 'IIT Madras', 'Assistant Professor', NULL, 'Specializing in Healthcare AI and Medical Imaging. Developed AI systems for early disease detection deployed in 50+ hospitals across India.', ARRAY['Healthcare AI', 'Medical Imaging', 'Deep Learning', 'Computer Vision'], ARRAY['AI for Diabetic Retinopathy Detection (2025)', 'Chest X-Ray Analysis using CNNs (2024)', 'Federated Learning in Healthcare (2023)'], 'https://linkedin.com/in/meerareddy', 'https://scholar.google.com/meerareddy', 2800, 32, 3, true, NOW(), NOW()),
