INSERT INTO "IndianAITool" (id, name, slug, tagline, description, "logoUrl", "websiteUrl", category, "foundedYear", "fundingStatus", "totalFunding", headquarters, "teamSize", features, "useCases", "isFeatured", "displayOrder", "isActive", "createdAt", "updatedAt")
VALUES
('tool-1', 'Sarvam AI', 'sarvam-ai', 'India''s first full-stack AI platform', 'Building foundation models and AI infrastructure specifically designed for Indian languages and use cases. Offers multilingual LLMs, speech-to-text, and text-to-speech capabilities.', NULL, 'https://sarvam.ai', 'LLM/Foundation Models', 2023, 'Series A', '$41M', 'Bangalore, Karnataka', '50-100', ARRAY['Multilingual LLM (10+ Indian languages)', 'Speech-to-text API', 'Text-to-speech synthesis', 'Real-time translation', 'Custom model fine-tuning'], ARRAY['Customer support automation', 'Content creation in regional languages', 'Voice assistants for Indian markets', 'Government service digitization'], true, 0, true, NOW(), NOW()),
('tool-2', 'Krutrim AI', 'krutrim-ai', 'India''s own AI', 'Building AI models trained on Indian data for Indian languages and cultural contexts. First Indian AI unicorn focused on indigenous AI development.', NULL, 'https://krutrim.ai', 'LLM/Foundation Models', 2023, 'Seed', '$50M', 'Bangalore, Karnataka', '100-200', ARRAY['Indic language support (20+ languages)', 'Cultural context understanding', 'Local data training', 'API access', 'Enterprise solutions'], ARRAY['Education technology', 'Healthcare diagnostics', 'Government services', 'Financial services'], true, 1, true, NOW(), NOW()),
('tool-3', 'Yellow.ai', 'yellow-ai', 'Enterprise conversational AI platform', 'AI-powered customer service automation platform serving 1000+ enterprises globally. Specializes in omnichannel customer engagement.', NULL, 'https://yellow.ai', 'Conversational AI', 2016, 'Series C', '$102M', 'Bangalore, Karnataka', '500+', ARRAY['Omnichannel support (chat, voice, email)', 'Voice bots with NLU', 'Chat automation', 'Analytics dashboard', 'CRM integrations', '100+ language support'], ARRAY['Customer support automation', 'Sales automation', 'HR automation', 'IT helpdesk'], false, 2, true, NOW(), NOW()),
('tool-4', 'Haptik', 'haptik', 'Conversational AI for enterprises', 'Leading conversational AI platform acquired by Reliance Jio. Powers customer engagement for major Indian brands.', NULL, 'https://haptik.ai', 'Conversational AI', 2013, 'Acquired', '$100M+', 'Mumbai, Maharashtra', '300+', ARRAY['Intelligent virtual assistants', 'WhatsApp Business API', 'Voice AI', 'Analytics & insights', 'Multi-language support'], ARRAY['E-commerce customer support', 'Banking & finance', 'Travel & hospitality', 'Retail automation'], false, 3, true, NOW(), NOW()),
('tool-5', 'Niramai', 'niramai', 'AI for breast cancer screening', 'Revolutionary AI-powered breast cancer screening solution using thermal imaging. Non-invasive, radiation-free, and affordable.', NULL, 'https://niramai.com', 'Healthcare AI', 2016, 'Series A', '$10M', 'Bangalore, Karnataka', '50-100', ARRAY['Thermal imaging analysis', 'AI-powered diagnosis', 'Cloud-based reporting', 'Mobile screening units', 'Privacy-preserving'], ARRAY['Early breast cancer detection', 'Rural healthcare screening', 'Corporate health programs', 'Hospital integration'], true, 4, true, NOW(), NOW());
INSERT INTO "FeaturedFounder" (id, name, "startupName", "startupSlug", "photoUrl", bio, achievement, "fundingRaised", category, "linkedinUrl", "twitterUrl", "storyUrl", "displayOrder", "isActive", "createdAt", "updatedAt")
VALUES
('founder-1', 'Vivek Raghavan', 'Sarvam AI', 'sarvam-ai', NULL, 'Former VP of Engineering at Flipkart, now building India''s first full-stack AI platform. IIT Madras alumnus with 15+ years in tech.', 'Raised $41M Series A to build foundation models for Indian languages. Previously led AI initiatives at Flipkart serving 300M+ users.', '$41M', 'Rising Star', 'https://linkedin.com/in/vivekraghavan', 'https://twitter.com/vivekraghavan', NULL, 0, true, NOW(), NOW()),
('founder-2', 'Bhavish Aggarwal', 'Krutrim AI', 'krutrim-ai', NULL, 'Founder of Ola Cabs, now building India''s own AI. IIT Bombay alumnus and one of India''s most successful entrepreneurs.', 'Launched India''s first indigenous AI model with $50M funding. Built Ola into a $6B+ company before pivoting to AI.', '$50M', 'Hall of Fame', 'https://linkedin.com/in/bhavishaggarwal', 'https://twitter.com/bhash', NULL, 1, true, NOW(), NOW()),
('founder-3', 'Raghu Ravinutala', 'Yellow.ai', 'yellow-ai', NULL, 'Serial entrepreneur and AI visionary. Previously co-founded multiple successful startups. Stanford alumnus.', 'Scaled Yellow.ai to $102M in funding and 500+ employees. Serving 1000+ enterprise customers globally including Domino''s, Sephora, and Hyundai.', '$102M', 'Featured', 'https://linkedin.com/in/raghuravinutala', 'https://twitter.com/raghur', NULL, 2, true, NOW(), NOW()),
('founder-4', 'Aakrit Vaish', 'Haptik', 'haptik', NULL, 'Co-founder of Haptik, acquired by Reliance Jio. IIT Roorkee alumnus. Forbes 30 Under 30 Asia.', 'Built Haptik from scratch to acquisition by Reliance Jio for $100M+. Now leading conversational AI for Jio''s 400M+ users.', '$100M+', 'Hall of Fame', 'https://linkedin.com/in/aakritvaish', 'https://twitter.com/aakritvaish', NULL, 3, true, NOW(), NOW()),
('founder-5', 'Geetha Manjunath', 'Niramai', 'niramai', NULL, 'PhD from IISc Bangalore. Former scientist at Xerox Research. Pioneer in AI for healthcare in India.', 'Developed AI-powered breast cancer screening solution deployed in 100+ centers. Raised $10M to make cancer screening accessible and affordable.', '$10M', 'Rising Star', 'https://linkedin.com/in/geethamanjunath', 'https://twitter.com/geethamanjunath', NULL, 4, true, NOW(), NOW());
